const canvas = document.createElement('canvas');
const ctx = canvas.getContext('2d');
document.body.style.margin = '0';
document.body.style.overflow = 'hidden';
document.body.style.background = '#111';
document.body.appendChild(canvas);

let W = window.innerWidth;
let H = window.innerHeight;
canvas.width = W;
canvas.height = H;

window.addEventListener('resize', () => {
  W = window.innerWidth;
  H = window.innerHeight;
  canvas.width = W;
  canvas.height = H;
});

const keys = Object.create(null);
window.addEventListener('keydown', e => {
  keys[e.key.toLowerCase()] = true;
});
window.addEventListener('keyup', e => {
  keys[e.key.toLowerCase()] = false;
});

const player = {
  x: W * 0.5,
  y: H * 0.5,
  angle: 0,
  speed: 0,
  maxSpeed: 420,
  accel: 900,
  friction: 700,
  turnSpeed: 3.2,
  radius: 16,
  distance: 0
};

const track = {
  points: [],
  width: 120
};

function generateTrack() {
  track.points.length = 0;
  const cx = W * 0.5;
  const cy = H * 0.5;
  const rx = Math.min(W, H) * 0.34;
  const ry = Math.min(W, H) * 0.22;
  const n = 120;
  for (let i = 0; i < n; i++) {
    const t = (i / n) * Math.PI * 2;
    const wobble = 1 + 0.12 * Math.sin(t * 3) + 0.08 * Math.cos(t * 5);
    track.points.push({
      x: cx + Math.cos(t) * rx * wobble,
      y: cy + Math.sin(t) * ry * wobble
    });
  }
}
generateTrack();

window.addEventListener('resize', generateTrack);

function drawTrack() {
  ctx.save();
  ctx.lineJoin = 'round';
  ctx.lineCap = 'round';

  ctx.strokeStyle = '#2b2b2b';
  ctx.lineWidth = track.width + 18;
  ctx.beginPath();
  track.points.forEach((p, i) => {
    if (i === 0) ctx.moveTo(p.x, p.y);
    else ctx.lineTo(p.x, p.y);
  });
  ctx.closePath();
  ctx.stroke();

  ctx.strokeStyle = '#555';
  ctx.lineWidth = track.width;
  ctx.beginPath();
  track.points.forEach((p, i) => {
    if (i === 0) ctx.moveTo(p.x, p.y);
    else ctx.lineTo(p.x, p.y);
  });
  ctx.closePath();
  ctx.stroke();

  ctx.setLineDash([24, 18]);
  ctx.strokeStyle = '#ddd';
  ctx.lineWidth = 4;
  ctx.beginPath();
  track.points.forEach((p, i) => {
    if (i === 0) ctx.moveTo(p.x, p.y);
    else ctx.lineTo(p.x, p.y);
  });
  ctx.closePath();
  ctx.stroke();
  ctx.setLineDash([]);

  ctx.restore();
}

function drawPlayer() {
  ctx.save();
  ctx.translate(player.x, player.y);
  ctx.rotate(player.angle);

  ctx.fillStyle = '#ffcc00';
  ctx.beginPath();
  ctx.moveTo(20, 0);
  ctx.lineTo(-14, -11);
  ctx.lineTo(-10, 0);
  ctx.lineTo(-14, 11);
  ctx.closePath();
  ctx.fill();

  ctx.fillStyle = '#222';
  ctx.beginPath();
  ctx.arc(-4, 0, 7, 0, Math.PI * 2);
  ctx.fill();

  ctx.restore();
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function update(dt) {
  if (keys['arrowleft'] || keys['a']) player.angle -= player.turnSpeed * dt;
  if (keys['arrowright'] || keys['d']) player.angle += player.turnSpeed * dt;

  if (keys['arrowup'] || keys['w']) {
    player.speed += player.accel * dt;
  } else if (keys['arrowdown'] || keys['s']) {
    player.speed -= player.accel * dt;
  } else {
    const sign = Math.sign(player.speed);
    const decel = player.friction * dt;
    if (Math.abs(player.speed) <= decel) player.speed = 0;
    else player.speed -= sign * decel;
  }

  player.speed = clamp(player.speed, -player.maxSpeed * 0.45, player.maxSpeed);

  const dx = Math.cos(player.angle) * player.speed * dt;
  const dy = Math.sin(player.angle) * player.speed * dt;
  player.x += dx;
  player.y += dy;
  player.distance += Math.hypot(dx, dy);

  if (player.x < 0) player.x = W;
  if (player.x > W) player.x = 0;
  if (player.y < 0) player.y = H;
  if (player.y > H) player.y = 0;
}

function render() {
  ctx.clearRect(0, 0, W, H);

  const bg = ctx.createLinearGradient(0, 0, 0, H);
  bg.addColorStop(0, '#0f1720');
  bg.addColorStop(1, '#101010');
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, W, H);

  drawTrack();
  drawPlayer();

  ctx.fillStyle = '#fff';
  ctx.font = '16px monospace';
  ctx.fillText(`Speed: ${player.speed.toFixed(1)} px/s`, 16, 24);
  ctx.fillText(`Distance: ${player.distance.toFixed(1)} px`, 16, 44);
  ctx.fillText(`Controls: WASD / Arrow Keys`, 16, 64);
}

let last = performance.now();
setInterval(() => {
  const now = performance.now();
  const dt = (now - last) / 1000;
  last = now;
  update(dt);
  render();
}, 1000 / 60);